  writer.writeDateTime(offsets[1], object.createdAt);
  writer.writeBool(offsets[2], object.isBuiltIn);
  writer.writeString(offsets[3], object.name);
  writer.writeString(offsets[4], object.nameJP);
  writer.writeLong(offsets[5], object.sortOrder);
  writer.writeString(offsets[6], object.uuid);
}

Category _categoryDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = Category();
  object.colorValue = reader.readLong(offsets[0]);
  object.createdAt = reader.readDateTime(offsets[1]);
  object.id = id;
  object.isBuiltIn = reader.readBool(offsets[2]);
  object.name = reader.readString(offsets[3]);
  object.nameJP = reader.readStringOrNull(offsets[4]);
  object.sortOrder = reader.readLong(offsets[5]);
  object.uuid = reader.readString(offsets[6]);
  return object;
}

